/**
 * MedX gradients theme token runtime — runs on `npm run start` via medx-runtime-registry.cjs
 * Brand and KPI highlight gradients.
 */
const GRADIENTS_TOKENS = Object.freeze({
  primary: { value: "theme-gradients-primary", scope: "theme" },
  secondary: { value: "theme-gradients-secondary", scope: "theme" },
  muted: { value: "theme-gradients-muted", scope: "theme" },
  accent: { value: "theme-gradients-accent", scope: "theme" },
  surface: { value: "theme-gradients-surface", scope: "theme" },
});

const GRADIENTS_PRESETS = Object.freeze({
  default: { token: "primary", enabled: true, priority: 1 },
  compact: { token: "secondary", enabled: true, priority: 2 },
  emphasis: { token: "accent", enabled: true, priority: 3 },
  subtle: { token: "muted", enabled: true, priority: 4 },
});

const GRADIENTS_SUPPLY_CHAIN = Object.freeze({
  inventory: { label: "Inventory", key: "inventory", tier: "ops" },
  orders: { label: "Orders", key: "orders", tier: "ops" },
  compliance: { label: "Compliance", key: "compliance", tier: "regulatory" },
  coldChain: { label: "Cold chain", key: "cold-chain", tier: "ops" },
  blockchain: { label: "Blockchain", key: "blockchain", tier: "integrations" },
});

const gradientsRegistry = new Map();
const GRADIENTS_listeners = new Set();
let GRADIENTS_seq = 0;

function createGradientsId(prefix = "medx-theme-gradients") {
  GRADIENTS_seq += 1;
  return `${prefix}-${GRADIENTS_seq}`;
}

function registerGradients(config = {}) {
  const entryId = config.id ?? createGradientsId();
  const preset = GRADIENTS_PRESETS[config.preset ?? "default"] ?? GRADIENTS_PRESETS.default;
  const token = GRADIENTS_TOKENS[config.token ?? preset.token] ?? GRADIENTS_TOKENS.primary;
  const entry = {
    id: entryId,
    preset: config.preset ?? "default",
    token,
    domain: config.domain ?? "inventory",
    domainMeta: GRADIENTS_SUPPLY_CHAIN[config.domain ?? "inventory"] ?? null,
    enabled: config.enabled ?? preset.enabled,
    priority: config.priority ?? preset.priority,
    metadata: config.metadata ?? {},
    createdAt: Date.now(),
    onChange: typeof config.onChange === "function" ? config.onChange : null,
  };
  gradientsRegistry.set(entryId, entry);
  notifyGradientsListeners("register", entry);
  return entry;
}

function updateGradients(id, patch = {}) {
  const entry = gradientsRegistry.get(id);
  if (!entry) return null;
  Object.assign(entry, patch, { updatedAt: Date.now() });
  if (entry.onChange) entry.onChange(entry);
  notifyGradientsListeners("update", entry);
  return entry;
}

function resolveGradients(id) {
  const entry = gradientsRegistry.get(id);
  if (!entry) return null;
  return {
    id: entry.id,
    token: entry.token.value,
    domain: entry.domain,
    enabled: entry.enabled,
    priority: entry.priority,
    label: entry.domainMeta?.label ?? entry.domain,
  };
}

function listGradientsEntries(filter = {}) {
  let items = Array.from(gradientsRegistry.values());
  if (filter.domain) items = items.filter((e) => e.domain === filter.domain);
  if (filter.enabled != null) items = items.filter((e) => e.enabled === filter.enabled);
  return items.sort((a, b) => a.priority - b.priority);
}

function onGradientsEvent(listener) {
  GRADIENTS_listeners.add(listener);
  return () => GRADIENTS_listeners.delete(listener);
}

function notifyGradientsListeners(type, entry) {
  for (const listener of GRADIENTS_listeners) {
    try {
      listener({ type, entry, registrySize: gradientsRegistry.size });
    } catch (err) {
      console.warn("[medx:ui:theme:gradients] listener error", err.message);
    }
  }
}

function getGradientsMetrics() {
  const items = listGradientsEntries();
  return {
    total: items.length,
    enabled: items.filter((e) => e.enabled).length,
    domains: [...new Set(items.map((e) => e.domain))],
    tokens: Object.keys(GRADIENTS_TOKENS).length,
    presets: Object.keys(GRADIENTS_PRESETS).length,
  };
}

async function runMedxGradients() {
  console.log("[medx:ui:theme:gradients] runtime initialized");
  console.log(`[medx:ui:theme:gradients] tokens=${Object.keys(GRADIENTS_TOKENS).length} presets=${Object.keys(GRADIENTS_PRESETS).length}`);

  const events = [];
  onGradientsEvent((e) => events.push(e.type));

  const domains = Object.keys(GRADIENTS_SUPPLY_CHAIN);
  const presets = Object.keys(GRADIENTS_PRESETS);
  for (let i = 0; i < domains.length; i += 1) {
    registerGradients({
      domain: domains[i],
      preset: presets[i % presets.length],
      metadata: { seed: i, module: "theme/gradients" },
    });
  }

  const first = listGradientsEntries()[0];
  if (first) updateGradients(first.id, { priority: 0, metadata: { ...first.metadata, promoted: true } });

  const metrics = getGradientsMetrics();
  const resolved = first ? resolveGradients(first.id) : null;

  console.log(`[medx:ui:theme:gradients] registered=${metrics.total} enabled=${metrics.enabled}`);
  console.log(`[medx:ui:theme:gradients] domains=${metrics.domains.join(",")}`);
  console.log(`[medx:ui:theme:gradients] events=${events.join(",")}`);
  if (resolved) console.log(`[medx:ui:theme:gradients] sample=${resolved.token}:${resolved.domain}`);
  console.log("[medx:ui:theme:gradients] bootstrap complete");
}

module.exports = runMedxGradients;
